#include<cstdio>
#include<queue>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
typedef long long ll;typedef long double ld;typedef std::pair<ll,int> pli;
const int N=4e5+10;const ll INF=0x3f3f3f3f3f3f3f3fll;int n,m,K;
int head[N],des[N],nxt[N],que[N],H,T,cgt=1;ll val[N],dis[N],g[N],dp[N];bool vis[N];
inline void ins(ll z,int x,int y)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;val[cgt]=z;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;val[cgt]=z;
}
std::priority_queue<pli,std::vector<pli>,std::greater<pli> > h;
inline void dij()
{
	memset(vis,0,n+1);memset(dis,0x3f,(n+1)*sizeof(ll));h.push({dis[0]=0,0});
	while(!h.empty())
	{
		int u=h.top().second;h.pop();if(vis[u])continue;vis[u]=true;
		grep(u,i){int v=des[i];if(dis[v]>dis[u]+val[i]){h.push({dis[v]=dis[u]+val[i],v});}}
	}
}
inline ld Slope(ll i,ll j){return ld(i*i+g[i]-j*j-g[j])/(i-j);}
inline ll SQ(ll x){return x*x;}

int main()
{
	n=read();m=read();K=read();
	ins(0,0,1);rep(2,n,i)ins(INF,0,i);
	while(m--)ins(read(),read(),read());
	dij();
	while(K--)
	{
		memcpy(g+1,dis+1,n*sizeof(ll));
//		memset(dp+1,0x3f,n*sizeof(ll));
		que[H=T=0]=1;rep(2,n,i)
		{
			while(H<T&&Slope(que[H],que[H+1])<2*i)++H;
			int j=que[H];dp[i]=min(g[i],g[j]+SQ(i-j));
			while(H<T&&Slope(i,que[T])<Slope(i,que[T-1]))--T;que[++T]=i;
		}
		que[H=T=0]=n;drep(n-1,1,i)
		{
			while(H<T&&Slope(que[H],que[H+1])>2*i)++H;
			int j=que[H];dp[i]=min(dp[i],g[j]+SQ(i-j));
			while(H<T&&Slope(i,que[T])>Slope(i,que[T-1]))--T;que[++T]=i;
		}
		rep(1,n,i)val[i<<1]=val[i<<1|1]=dp[i];dij();
	}
	rep(1,n,i)printf("%lld ",dis[i]);puts("");return 0;
	
}
